	lim := NewLimiter(Config{Rate: 2, Window: time.Second}, clock)

	// Exhaust key "x".
	lim.Allow("x")
	lim.Allow("x")
	if lim.Allow("x") {
		t.Fatal("should be denied after exhausting rate")
	}

	// Exhaust key "y".
	lim.Allow("y")
	lim.Allow("y")

	// Reset only "x".
	lim.Reset("x")

	// "x" should be allowed again.
	if !lim.Allow("x") {
