			b = &bucketState{
				lastSeen: l.clk.Now(),
				tokens:   l.cfg.Burst, // start full
			}
			l.state[key] = b
		}
		l.mu.Unlock()
	}

	b.mu.Lock()
	defer b.mu.Unlock()

	now := l.clk.Now()
	if now.After(b.lastSeen) {
		elapsed := now.Sub(b.lastSeen)
		if elapsed >= l.cfg.Window {
			whole := int(elapsed / l.cfg.Window)
			add := whole * l.cfg.Rate
			if add > 0 {
				b.tokens += add
				if b.tokens > l.cfg.Burst {
					b.tokens = l.cfg.Burst
				}
				// advance lastSeen by whole windows
				b.lastSeen = b.lastSeen.Add(time.Duration(whole) * l.cfg.Window)
			}
		}
	}

	if b.tokens <= 0 {
		return false
	}
	b.tokens--
	return true
}

// Reset clears the rate‑limiting state for a specific key.
func (l *bucketLimiter) Reset(key string) {
	l.mu.Lock()
	delete(l.state, key)
	l.mu.Unlock()
}
